INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0', $q$Encrypted task management$q$, $q$Tasks, subtasks, and priorities are stored end-to-end encrypted and organized into customizable 'Areas of Life' with list, Kanban, and Eisenhower Matrix views.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0', $q$Habit and mood tracking$q$, $q$Log daily habits and moods, then review charts that surface correlations between specific habits and reported mood or energy levels.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0', $q$Private journaling$q$, $q$Write encrypted journal entries tagged with mood and emotion, kept separate from tasks so reflection does not get lost in a to-do list.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0', $q$Personal CRM$q$, $q$Track relationships and set reminders to follow up with contacts, useful for maintaining personal or professional connections without a dedicated CRM tool.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0', $q$Cross-platform sync$q$, $q$Native apps for macOS, Windows, Linux, iOS, and Android keep tasks, habits, notes, and journal entries synced across every device.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0', $q$ADHD-oriented prioritization$q$, $q$A 'now/next/later' style workflow and forced prioritization limits reduce the overwhelm of long backlog lists, a design choice aimed squarely at ADHD users.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0', $q$Calendar integration$q$, $q$Premium subscribers can connect external calendars to see tasks and events side by side and schedule work around existing commitments.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0', $q$Notes$q$, $q$A dedicated encrypted notes module sits alongside tasks and journal entries for capturing freeform information.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0', $q$True end-to-end encryption means Lunatask itself cannot read your tasks, journal, or notes.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0', $q$ADHD-specific design (forced prioritization, reduced clutter) is uncommon among mainstream task managers.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0', $q$Combines task management, habit tracking, journaling, and a personal CRM in one app instead of several.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0', $q$One-time lifetime purchase option avoids an open-ended subscription.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0', $q$Native apps across macOS, Windows, Linux, iOS, and Android.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0', $q$No team or collaboration features, so it is not suitable for shared work management.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0', $q$Free plan is fairly limited (2 Areas of Life, 7 habits, 30 CRM contacts, no calendar sync).$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0', $q$Smaller ecosystem and fewer third-party integrations than established players like Todoist or Notion.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0', $q$Built and maintained by a very small, largely solo team, which can mean slower feature velocity.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0', $q$Encryption model limits some convenience features, such as server-side search, common in non-encrypted apps.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0', $q$Is Lunatask free to use?$q$, $q$Yes, Lunatask has a permanently free tier, but it limits users to 2 Areas of Life, 7 daily habits, and 30 CRM relationships, and it excludes calendar integration. Unlocking all features requires the Premium plan.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0', $q$How does Lunatask's encryption work?$q$, $q$Lunatask encrypts tasks, journal entries, notes, and habit data on the user's device using keys derived with the argon2 algorithm before syncing to Lunatask Cloud over TLS 1.3, so the company cannot read stored content.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0', $q$Does Lunatask support teams?$q$, $q$No, Lunatask is designed for individual use and does not offer shared workspaces, team task assignment, or multi-user administration.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0', $q$What platforms does Lunatask run on?$q$, $q$Lunatask has native apps for macOS, Windows, Linux, iOS, and Android, with data synced across all of them.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0', $q$Is there a lifetime plan?$q$, $q$Yes, Lunatask offers a one-time lifetime Premium purchase for $300 in addition to its $8/month or $72/year subscription.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0', $q$Who makes Lunatask?$q$, $q$Lunatask was built by independent developer Carl Pullein, who created the app in 2021 after struggling with ADHD and finding existing task managers overwhelming.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0', $q$ADHD-friendly task management$q$, $q$Individuals with ADHD use Lunatask's forced prioritization and reduced-clutter views to avoid the overwhelm of long backlog lists.$q$, $q$Neurodivergent professionals and students$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0', $q$Privacy-conscious personal productivity$q$, $q$Users who do not want their tasks, journal, or notes readable by a vendor choose Lunatask for its end-to-end encryption.$q$, $q$Privacy-focused knowledge workers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0', $q$Habit and mood correlation tracking$q$, $q$People trying to build habits use Lunatask to log daily habits alongside mood, then review patterns to see what routines actually improve wellbeing.$q$, $q$Self-improvement and wellness-focused individuals$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["2 Areas of Life","Up to 7 daily habits","Up to 30 CRM relationships","No calendar integration"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0', $q$Premium Monthly$q$, $q$$8/month$q$, $q$monthly$q$, NULL, $q$["Unlimited Areas of Life","Unlimited habits","Unlimited CRM relationships","Calendar integration","All views including Kanban and Eisenhower Matrix"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0', $q$Premium Yearly$q$, $q$$72/year$q$, $q$yearly$q$, NULL, $q$["Same as Premium Monthly","Effective price of $6/month"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0', $q$Lifetime Premium$q$, $q$$300$q$, $q$one-time$q$, NULL, $q$["All Premium features","No recurring payment"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Lunatask is a cross-platform personal productivity app that unifies task management, habit tracking, journaling, notes, and a simple personal CRM into one encrypted workspace. It was created by independent developer Carl Pullein and launched in 2021 with a specific focus on users who have ADHD or who feel overwhelmed by traditional, list-heavy to-do apps.$q$, $q$Rather than presenting an endless backlog, Lunatask nudges users toward a small, prioritized set of 'now' tasks using views like the Eisenhower Matrix and Kanban boards, while habit and mood tracking help surface behavioral patterns over time. The app runs natively on macOS, Windows, Linux, iOS, and Android with data synced across devices.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At the center of Lunatask is its task manager, which lets users group work into 'Areas of Life,' apply priority scoring, and switch between list, Kanban, and Eisenhower Matrix views. A built-in habit tracker logs daily habits and mood, and highlights correlations between the two, while the journaling feature supports private, tagged entries for reflection.$q$, $q$Lunatask's standout feature is its end-to-end encryption: tasks, notes, journal entries, and habit data are encrypted on-device using argon2-derived keys before syncing, so Lunatask's own servers never see readable user data. It also includes a lightweight personal CRM for tracking relationships and follow-ups, and calendar integration on paid plans.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Lunatask follows a freemium model. The free plan has no time limit but restricts users to 2 Areas of Life, 7 daily habits, and 30 CRM relationships, and excludes calendar sync. Premium removes these caps and adds calendar integration for $8/month or $72/year.$q$, $q$Unusually for a modern subscription app, Lunatask also sells a one-time lifetime Premium license for $300, giving budget-conscious or subscription-averse users a way to unlock every feature permanently.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9b18967c-f6f6-453b-8f0e-8b8d312dfe53', $q$Bank and investment account sync$q$, $q$Automatically pulls in transactions and balances from linked bank, credit card, and investment accounts.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9b18967c-f6f6-453b-8f0e-8b8d312dfe53', $q$Multi-currency support$q$, $q$Tracks accounts and transactions in different currencies and converts them into a home currency for unified reporting.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9b18967c-f6f6-453b-8f0e-8b8d312dfe53', $q$Crypto tracking$q$, $q$Manually or semi-automatically tracks cryptocurrency holdings alongside traditional accounts.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9b18967c-f6f6-453b-8f0e-8b8d312dfe53', $q$Budgeting tools$q$, $q$Supports category-based and zero-based budgeting with rollover rules and spending trend views.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9b18967c-f6f6-453b-8f0e-8b8d312dfe53', $q$Shared budgets$q$, $q$Allows couples or households to share visibility into joint budgets and accounts.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9b18967c-f6f6-453b-8f0e-8b8d312dfe53', $q$Recurring bill tracking$q$, $q$Detects and tracks recurring transactions so users can anticipate upcoming bills.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9b18967c-f6f6-453b-8f0e-8b8d312dfe53', $q$Public API$q$, $q$Offers a documented API for developers to build custom automations or integrate Lunch Money data with other tools.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9b18967c-f6f6-453b-8f0e-8b8d312dfe53', $q$Pay-what-you-want pricing$q$, $q$Lets subscribers choose and lock in their own subscription price rather than being forced into fixed tiers.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9b18967c-f6f6-453b-8f0e-8b8d312dfe53', $q$Pay-what-you-want pricing model lets long-time users lock in lower rates.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9b18967c-f6f6-453b-8f0e-8b8d312dfe53', $q$Strong multi-currency and cryptocurrency tracking not always found in mainstream budgeting apps.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9b18967c-f6f6-453b-8f0e-8b8d312dfe53', $q$Bootstrapped, founder-led company with a track record of responsive support.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9b18967c-f6f6-453b-8f0e-8b8d312dfe53', $q$Public API appeals to technically inclined users who want custom automations.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9b18967c-f6f6-453b-8f0e-8b8d312dfe53', $q$All subscribers get the full feature set, with no feature-gated tiers.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9b18967c-f6f6-453b-8f0e-8b8d312dfe53', $q$No permanent free tier, only a free trial before payment is required.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9b18967c-f6f6-453b-8f0e-8b8d312dfe53', $q$Smaller company than venture-backed competitors like Monarch Money, which may mean fewer resources for rapid feature development.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9b18967c-f6f6-453b-8f0e-8b8d312dfe53', $q$Bank-sync reliability depends on third-party aggregation providers and can occasionally break.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9b18967c-f6f6-453b-8f0e-8b8d312dfe53', $q$Pay-what-you-want pricing can be confusing for users unsure what a fair price is.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9b18967c-f6f6-453b-8f0e-8b8d312dfe53', $q$No native investment advisory or robo-advisor features, unlike some finance apps.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b18967c-f6f6-453b-8f0e-8b8d312dfe53', $q$Is Lunch Money free?$q$, $q$Lunch Money offers a free trial, but after that it requires a paid, pay-what-you-want annual subscription; there is no permanent free tier.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b18967c-f6f6-453b-8f0e-8b8d312dfe53', $q$What does 'pay-what-you-want' mean for Lunch Money pricing?$q$, $q$Subscribers choose their own price above a minimum threshold, and that price is locked in for as long as they remain subscribed, rather than being assigned a fixed tier.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b18967c-f6f6-453b-8f0e-8b8d312dfe53', $q$Does Lunch Money support multiple currencies?$q$, $q$Yes, Lunch Money can track accounts and transactions in different currencies and converts them into a home currency for consolidated budgeting and reporting.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b18967c-f6f6-453b-8f0e-8b8d312dfe53', $q$Can Lunch Money track cryptocurrency?$q$, $q$Yes, Lunch Money supports tracking crypto holdings alongside traditional bank and investment accounts.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b18967c-f6f6-453b-8f0e-8b8d312dfe53', $q$Who built Lunch Money?$q$, $q$Lunch Money was founded by Jen Yip, who built the app after manually tracking her own multi-currency spending in a spreadsheet, and launched it publicly in 2019.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b18967c-f6f6-453b-8f0e-8b8d312dfe53', $q$Does Lunch Money have an API?$q$, $q$Yes, Lunch Money provides a public API that developers can use to build custom integrations and automations.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9b18967c-f6f6-453b-8f0e-8b8d312dfe53', $q$Multi-currency personal budgeting$q$, $q$Travelers, expats, and digital nomads use Lunch Money to track spending across multiple currencies in one consolidated budget.$q$, $q$Expats and frequent travelers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9b18967c-f6f6-453b-8f0e-8b8d312dfe53', $q$Household budgeting$q$, $q$Couples share a Lunch Money budget to track joint spending and savings goals together.$q$, $q$Couples and households$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9b18967c-f6f6-453b-8f0e-8b8d312dfe53', $q$Custom finance automation$q$, $q$Developers and power users pull Lunch Money data via its API into spreadsheets or other tools for custom reporting.$q$, $q$Technically inclined power users$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9b18967c-f6f6-453b-8f0e-8b8d312dfe53', $q$Free Trial$q$, $q$$0$q$, $q$trial$q$, NULL, $q$["Full feature access during trial","Bank sync","Budgeting tools"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9b18967c-f6f6-453b-8f0e-8b8d312dfe53', $q$Pay-What-You-Want Annual$q$, $q$User-chosen, subject to a minimum; originally $29/year at launch$q$, $q$yearly$q$, NULL, $q$["Full feature set","Price locked in for the life of the subscription","Multi-currency and crypto tracking","Shared budgets","API access"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9b18967c-f6f6-453b-8f0e-8b8d312dfe53', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Lunch Money is a personal finance and budgeting app that connects to bank, credit card, investment, and cryptocurrency accounts to give users a single, multi-currency view of spending and net worth. It was created by founder Jen Yip after she spent a year and a half tracking her own travel spending in a multi-currency spreadsheet, and launched publicly in 2019.$q$, $q$The company is bootstrapped, self-funded entirely by subscriptions, and for its first several years was run by Yip alone. Lunch Money is aimed at people who find automated apps too rigid and spreadsheets too manual, particularly freelancers, remote workers, and users who deal with more than one currency.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9b18967c-f6f6-453b-8f0e-8b8d312dfe53', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Lunch Money links to banks and investment accounts through account aggregation, and also supports manually tracked accounts for cash and crypto holdings. Users can build category or zero-based budgets, tag and split transactions, and set up recurring bill tracking.$q$, $q$Multi-currency support is a core differentiator: balances and transactions in different currencies are converted into a home currency for reporting, which is useful for expats, travelers, and crypto holders. Lunch Money also offers shared budgets for couples or households and a public API for custom integrations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9b18967c-f6f6-453b-8f0e-8b8d312dfe53', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Lunch Money uses a pay-what-you-want annual subscription after a free trial: users pick their own price above a minimum, and that price is locked in for as long as they stay subscribed, rather than being tiered by feature.$q$, $q$The app launched in 2019 at $3/month ($29/year); typical suggested pricing has increased since then, but because pricing is user-chosen and locked in, actual cost varies by subscriber, and all subscribers get access to the same full feature set.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$Browser extension enrichment$q$, $q$Reveals verified emails and phone numbers directly on LinkedIn and company websites through a Chrome extension.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$Verified contact database$q$, $q$Combines crowd-sourced contributions with verification processes to maintain accuracy of emails and direct-dial phone numbers.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$Company and intent data$q$, $q$Provides firmographic details and buying-intent signals to help prioritize which accounts to target.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$CRM integrations$q$, $q$Native integrations with Salesforce, HubSpot, and other CRMs sync enriched contact data directly into existing sales workflows.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$Lusha Engage$q$, $q$Built-in outreach sequencing tool for running multi-step email and call campaigns from within Lusha.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$Lusha Conversations$q$, $q$Call intelligence features that record, transcribe, and analyze sales calls.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$API access$q$, $q$REST API for bulk or programmatic contact and company enrichment integrated into custom tools.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$Credit-based plans$q$, $q$Flexible per-user credit allowances scale from a free tier through custom enterprise pricing.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$Lower entry price than large incumbents like ZoomInfo, with a usable free tier.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$Browser extension makes prospecting fast without leaving LinkedIn or a company website.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$Includes outreach (Engage) and call intelligence (Conversations) beyond pure contact lookup.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$Well-funded, established company with strong CRM integrations.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$Credit system lets teams control spend by only paying for reveals they actually use.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$Credit-based pricing can get expensive quickly for teams doing high-volume phone-number lookups.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$Phone-number reveal costs increased under recent pricing changes, raising effective per-contact cost.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$Data coverage and accuracy can vary by region compared to email accuracy.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$Enterprise-scale pricing on the Scale plan is not published and requires a custom quote.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$Some users report the free plan's 40 monthly credits are consumed very quickly.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$Is Lusha free to use?$q$, $q$Lusha has a permanently free plan that includes 40 credits per month for a single user, along with the browser extension and basic CRM integrations.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$How does Lusha's credit system work?$q$, $q$Each contact reveal uses credits; revealing an email typically costs fewer credits than revealing a phone number, and paid plans include larger monthly credit allowances.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$What is Lusha used for?$q$, $q$Lusha is used primarily by sales, recruiting, and marketing teams to find and verify contact details for prospects and to run outreach campaigns.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$Who founded Lusha?$q$, $q$Lusha was founded in 2016 in Tel Aviv, Israel, by Yoni Tserruya and Assaf Eisenstein.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$How much funding has Lusha raised?$q$, $q$Lusha has raised approximately $245 million in total funding, including a $205 million Series B round in 2021 that valued the company at about $1.5 billion.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$What are Lusha's main competitors?$q$, $q$Lusha competes primarily with ZoomInfo, Apollo.io, Cognism, and Seamless.AI in the B2B sales intelligence space.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$Outbound sales prospecting$q$, $q$SDRs and account executives use Lusha's browser extension to find verified emails and phone numbers for cold outreach.$q$, $q$Sales development reps and account executives$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$Recruiting and candidate sourcing$q$, $q$Recruiters use Lusha to find direct contact details for passive candidates found on LinkedIn.$q$, $q$Technical and executive recruiters$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$Account-based marketing$q$, $q$Marketing teams use Lusha's company and intent data to prioritize target accounts and build enriched contact lists.$q$, $q$B2B marketing and demand generation teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["40 credits per month","1 user","Browser extension","Basic CRM integrations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$Starter$q$, $q$About $37.45/month per user billed annually (about $49.90 billed monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Around 400 credits per month","Browser extension","Email and phone reveals"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$Pro$q$, $q$About $52.45/month per user billed annually (about $69.90 billed monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Around 600 credits per month","CRM integrations","Team management"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$Premium$q$, $q$About $299.95/month per user billed annually (about $399.90 billed monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Around 3400 credits per month","Advanced filters","Priority support"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$Scale$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["Custom credit volume","Enterprise administration","Dedicated support"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Lusha is a B2B sales intelligence platform that provides verified email addresses, phone numbers, and company data to help sales, recruiting, and marketing teams find and reach prospects. It was founded in 2016 in Tel Aviv, Israel, by Yoni Tserruya and Assaf Eisenstein and has since raised roughly $245 million in funding, reaching a valuation of about $1.5 billion after its 2021 Series B round.$q$, $q$The company operates a crowd-sourced and verified contact database accessed mainly through a browser extension, alongside a web app, CRM integrations, and an API, and has expanded into sales engagement with its Engage and Conversations products.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Lusha's browser extension overlays verified contact details directly onto LinkedIn profiles and company websites, letting users reveal emails and phone numbers without leaving their existing workflow. The platform also provides company-level firmographic and intent data to help prioritize accounts.$q$, $q$Beyond contact lookup, Lusha includes Lusha Engage for building and running outreach sequences and Lusha Conversations for call intelligence, plus native integrations with CRMs like Salesforce and HubSpot and an API for bulk enrichment.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cb38ef74-ed67-4950-a546-3ece2c203f18', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Lusha uses a freemium, credit-based model: the free plan gives one user 40 credits per month, while paid Starter, Pro, and Premium plans provide increasing monthly credit allowances, priced per user and cheaper when billed annually versus monthly.$q$, $q$Each contact reveal consumes credits, with emails costing fewer credits than phone numbers under the current rate structure. Larger sales organizations can move to the custom-priced Scale plan for higher volume and additional administrative controls.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('afe3197a-f0df-4980-b89c-90bb6be2715d', $q$Multi-format streaming$q$, $q$Streams MP3, FLAC, WAV, Ogg Vorbis, Opus, and AAC files from a local library to any number of connected players.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('afe3197a-f0df-4980-b89c-90bb6be2715d', $q$Synchronized multi-room audio$q$, $q$Groups multiple players to play music in sync across different rooms.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('afe3197a-f0df-4980-b89c-90bb6be2715d', $q$Broad platform support$q$, $q$Runs on Linux, Windows, macOS, BSD, and popular NAS platforms like Synology and QNAP.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('afe3197a-f0df-4980-b89c-90bb6be2715d', $q$Squeezebox hardware compatibility$q$, $q$Continues to support the original Logitech Squeezebox hardware players alongside modern software clients.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('afe3197a-f0df-4980-b89c-90bb6be2715d', $q$Plugin architecture$q$, $q$Extends the server with community plugins for internet radio, streaming integrations, and custom features.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('afe3197a-f0df-4980-b89c-90bb6be2715d', $q$Web-based administration$q$, $q$Manages the music library, players, and settings through a browser-based interface.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('afe3197a-f0df-4980-b89c-90bb6be2715d', $q$Software player support$q$, $q$Works with third-party software players such as Squeezelite and apps like Material Skin.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('afe3197a-f0df-4980-b89c-90bb6be2715d', $q$Community-driven development$q$, $q$Actively maintained by the volunteer LMS-Community rather than a commercial vendor.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('afe3197a-f0df-4980-b89c-90bb6be2715d', $q$Completely free and open source with no subscriptions or licensing costs.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('afe3197a-f0df-4980-b89c-90bb6be2715d', $q$Long track record dating back over two decades, with a mature, stable codebase.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('afe3197a-f0df-4980-b89c-90bb6be2715d', $q$Strong multi-room, synchronized playback across many player types.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('afe3197a-f0df-4980-b89c-90bb6be2715d', $q$Continues to support legacy Squeezebox hardware that would otherwise be unsupported.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('afe3197a-f0df-4980-b89c-90bb6be2715d', $q$Runs on inexpensive hardware like NAS devices and Raspberry Pi.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('afe3197a-f0df-4980-b89c-90bb6be2715d', $q$Interface and setup are more technical than commercial alternatives like Plex or Roon.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('afe3197a-f0df-4980-b89c-90bb6be2715d', $q$Relies entirely on volunteer maintainers, with no commercial support option.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('afe3197a-f0df-4980-b89c-90bb6be2715d', $q$Client and player ecosystem has shrunk since original Squeezebox hardware was discontinued.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('afe3197a-f0df-4980-b89c-90bb6be2715d', $q$Written in Perl, an aging language stack compared to some newer self-hosted media servers.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('afe3197a-f0df-4980-b89c-90bb6be2715d', $q$Less polished mobile app experience compared to modern competitors like Plex or Navidrome.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('afe3197a-f0df-4980-b89c-90bb6be2715d', $q$Is Lyrion Music Server free?$q$, $q$Yes, Lyrion Music Server is entirely free and open source under the GNU General Public License, with no paid tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('afe3197a-f0df-4980-b89c-90bb6be2715d', $q$What was Lyrion Music Server called before?$q$, $q$It was previously known as Logitech Media Server, and before that SqueezeCenter and SlimServer, before the community rebranded it to Lyrion Music Server in November 2024 with version 9.0.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('afe3197a-f0df-4980-b89c-90bb6be2715d', $q$Do I need Squeezebox hardware to use Lyrion Music Server?$q$, $q$No, Lyrion Music Server works with software players like Squeezelite and various mobile and desktop apps in addition to legacy Squeezebox hardware.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('afe3197a-f0df-4980-b89c-90bb6be2715d', $q$What audio formats does Lyrion Music Server support?$q$, $q$It supports MP3, FLAC, WAV, Ogg Vorbis, Opus, and AAC, among other formats.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('afe3197a-f0df-4980-b89c-90bb6be2715d', $q$Who maintains Lyrion Music Server?$q$, $q$It is maintained by the volunteer LMS-Community on GitHub, following Logitech's withdrawal from active development after version 7.7.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('afe3197a-f0df-4980-b89c-90bb6be2715d', $q$Can Lyrion Music Server run on a NAS?$q$, $q$Yes, it is commonly installed on NAS devices from Synology and QNAP, as well as on minimal Linux distributions built for audio streaming.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('afe3197a-f0df-4980-b89c-90bb6be2715d', $q$Whole-home audio streaming$q$, $q$Audiophiles run Lyrion Music Server on a home server or NAS to stream a local music library to multiple synchronized rooms.$q$, $q$Home audio enthusiasts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('afe3197a-f0df-4980-b89c-90bb6be2715d', $q$Reviving legacy Squeezebox hardware$q$, $q$Owners of older Squeezebox players use Lyrion Music Server to keep their hardware working after Logitech ended official support.$q$, $q$Owners of legacy Squeezebox devices$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('afe3197a-f0df-4980-b89c-90bb6be2715d', $q$Self-hosted music library management$q$, $q$Users who prefer owning their music files over relying solely on streaming services self-host Lyrion to organize and stream their collection.$q$, $q$Self-hosting and open-source hobbyists$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('afe3197a-f0df-4980-b89c-90bb6be2715d', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full server functionality","Multi-room sync","Plugin support","Community support only"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('afe3197a-f0df-4980-b89c-90bb6be2715d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Lyrion Music Server is a free, open-source media server descended from Logitech Media Server, formerly SlimServer and Squeezebox Server, tracing back to Slim Devices' original SLIMP3 player software from 2001. Logitech acquired Slim Devices in 2006 and ran the project until stepping back after version 7.7, at which point a volunteer community took over development.$q$, $q$The project was rebranded from Logitech Media Server to Lyrion Music Server with version 9.0 in November 2024, following the shutdown of Logitech's mysqueezebox.com cloud service, marking a full and formal separation from the Logitech brand while preserving compatibility with the existing Squeezebox hardware and software ecosystem.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('afe3197a-f0df-4980-b89c-90bb6be2715d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Lyrion Music Server indexes a local digital music library and streams it to any number of connected players in formats including MP3, FLAC, WAV, Ogg Vorbis, Opus, and AAC, with support for synchronized, multi-room playback across grouped devices.$q$, $q$It runs on Linux, Windows, macOS, and BSD, and is popular on NAS devices from Synology and QNAP as well as minimal Linux images like piCorePlayer. A plugin architecture supports internet radio and additional streaming integrations, and it remains compatible with both original Squeezebox hardware and modern software players.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('afe3197a-f0df-4980-b89c-90bb6be2715d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Lyrion Music Server is entirely free and open source, licensed under the GNU General Public License, with no paid tiers, subscriptions, or licensing fees of any kind.$q$, $q$Because it is self-hosted, the only costs involved are for the hardware running the server, such as a home server, NAS, or Raspberry Pi, and any player hardware or software used to listen to the streamed music.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('afe3197a-f0df-4980-b89c-90bb6be2715d', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('afe3197a-f0df-4980-b89c-90bb6be2715d', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a6963e7b-5db0-4f3f-a759-a0c758f52263', $q$Real-time usage metering$q$, $q$Ingests high-volume usage events in real time to power accurate, up-to-date consumption tracking.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a6963e7b-5db0-4f3f-a759-a0c758f52263', $q$Multi-dimensional rating engine$q$, $q$Applies tiered, graduated, per-unit, and hybrid pricing logic across multiple usage metrics simultaneously.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a6963e7b-5db0-4f3f-a759-a0c758f52263', $q$Automated, auditable billing$q$, $q$Generates error-checked bills with a full audit trail to reduce billing disputes and revenue leakage.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a6963e7b-5db0-4f3f-a759-a0c758f52263', $q$Downstream integrations$q$, $q$Connects to invoicing, CRM, and revenue-recognition systems including Salesforce, NetSuite, and Stripe Billing.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a6963e7b-5db0-4f3f-a759-a0c758f52263', $q$Agentforce Revenue Management integration$q$, $q$Following its Salesforce acquisition, m3ter technology now underpins consumption and outcome-based billing for AI agents within Salesforce's platform.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a6963e7b-5db0-4f3f-a759-a0c758f52263', $q$Flexible pricing models$q$, $q$Supports usage-based, hybrid subscription-plus-usage, and outcome-based pricing structures.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a6963e7b-5db0-4f3f-a759-a0c758f52263', $q$Enterprise-scale architecture$q$, $q$Designed to handle very high transaction and event volumes for large software companies.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a6963e7b-5db0-4f3f-a759-a0c758f52263', $q$Rapid proof-of-concept setup$q$, $q$Can stand up initial pricing model proofs of concept within days ahead of a fuller rollout.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a6963e7b-5db0-4f3f-a759-a0c758f52263', $q$Purpose-built, deep metering and rating engine for complex usage-based pricing models.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a6963e7b-5db0-4f3f-a759-a0c758f52263', $q$Now backed by Salesforce's resources and distribution following the 2026 acquisition.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a6963e7b-5db0-4f3f-a759-a0c758f52263', $q$Handles very high volumes of usage events with real-time processing.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a6963e7b-5db0-4f3f-a759-a0c758f52263', $q$Strong downstream integrations with major CRM, invoicing, and revenue-recognition systems.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a6963e7b-5db0-4f3f-a759-a0c758f52263', $q$Fast proof-of-concept timelines relative to full quote-to-cash transformations.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a6963e7b-5db0-4f3f-a759-a0c758f52263', $q$No public, self-serve pricing; only suited to enterprises able to commit to custom, typically six-figure contracts.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a6963e7b-5db0-4f3f-a759-a0c758f52263', $q$Focuses narrowly on metering and rating rather than the full billing and payments stack, requiring additional tools for invoicing and collections.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a6963e7b-5db0-4f3f-a759-a0c758f52263', $q$Post-acquisition roadmap and standalone product direction are now tied to Salesforce's broader strategy.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a6963e7b-5db0-4f3f-a759-a0c758f52263', $q$Full implementations can take three to six months as part of larger transformation projects.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a6963e7b-5db0-4f3f-a759-a0c758f52263', $q$Not accessible to small startups or teams needing lightweight, self-serve usage billing.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a6963e7b-5db0-4f3f-a759-a0c758f52263', $q$What does m3ter do?$q$, $q$m3ter is a usage-metering and rating platform that helps software companies process consumption data and generate accurate, auditable bills for usage-based and hybrid pricing models.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a6963e7b-5db0-4f3f-a759-a0c758f52263', $q$Who owns m3ter now?$q$, $q$Salesforce acquired m3ter, signing a definitive agreement in June 2026 and closing the deal on July 1, 2026, integrating its technology into Agentforce Revenue Management.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a6963e7b-5db0-4f3f-a759-a0c758f52263', $q$How much does m3ter cost?$q$, $q$m3ter does not publish pricing; it uses custom enterprise contracts that typically represent six-figure annual commitments.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a6963e7b-5db0-4f3f-a759-a0c758f52263', $q$Who founded m3ter?$q$, $q$m3ter was founded in 2020 in London by Griffin Parry and John Griffin, who previously co-founded GameSparks, acquired by Amazon in 2017.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a6963e7b-5db0-4f3f-a759-a0c758f52263', $q$Is m3ter a full billing platform?$q$, $q$No, m3ter focuses specifically on usage metering and rating, integrating with separate invoicing, payments, and revenue-recognition tools to complete the billing process.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a6963e7b-5db0-4f3f-a759-a0c758f52263', $q$What are m3ter's main competitors?$q$, $q$m3ter competes with Metronome, Amberflo, Togai, Orb, and larger billing platforms like Zuora, Chargebee, and BillingPlatform.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a6963e7b-5db0-4f3f-a759-a0c758f52263', $q$Consumption-based SaaS billing$q$, $q$Software companies use m3ter to meter API calls, compute usage, or other consumption metrics and translate them into accurate invoices.$q$, $q$Enterprise SaaS and API-first companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a6963e7b-5db0-4f3f-a759-a0c758f52263', $q$Hybrid subscription-plus-usage pricing$q$, $q$Companies combining flat subscription fees with usage overages use m3ter to manage the rating complexity.$q$, $q$Mid-market to enterprise software vendors$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a6963e7b-5db0-4f3f-a759-a0c758f52263', $q$AI agent and outcome-based billing$q$, $q$Following its Salesforce acquisition, m3ter's technology helps companies bill for AI agent usage and outcome-based pricing models within Agentforce Revenue Management.$q$, $q$Salesforce customers adopting agentic AI pricing$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a6963e7b-5db0-4f3f-a759-a0c758f52263', $q$Enterprise (Custom)$q$, $q$Custom quote, typically six-figure annual contracts$q$, $q$annual contract$q$, NULL, $q$["Real-time usage metering","Multi-dimensional rating engine","Downstream billing integrations","Dedicated implementation support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a6963e7b-5db0-4f3f-a759-a0c758f52263', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$m3ter is an enterprise usage-metering and rating platform for software companies running consumption-based or hybrid pricing models. Founded in 2020 in London by Griffin Parry and John Griffin, former co-founders of GameSparks, which was acquired by Amazon in 2017, m3ter raised roughly $33 million from investors including Union Square Ventures, Insight Partners, and Notion Capital before being acquired.$q$, $q$In 2026, Salesforce signed a definitive agreement to acquire m3ter, closing the deal on July 1, 2026, and folding its metering and rating technology into Agentforce Revenue Management to support consumption- and outcome-based billing for AI agents and other usage-priced products across the Salesforce platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a6963e7b-5db0-4f3f-a759-a0c758f52263', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$m3ter is built to ingest usage events at high volume in real time and apply complex, multi-dimensional pricing logic, including tiered, graduated, and hybrid pricing across multiple usage metrics, then generate accurate, auditable bills.$q$, $q$Rather than covering the entire billing and payments stack, m3ter focuses specifically on the metering and rating layer, integrating with downstream invoicing, CRM, and revenue-recognition systems such as Salesforce, NetSuite, and Stripe Billing to complete the quote-to-cash process.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a6963e7b-5db0-4f3f-a759-a0c758f52263', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$m3ter does not publish self-serve pricing; all plans are custom-quoted for enterprise customers, and typical contracts represent six-figure annual commitments reflecting its focus on mid-market and enterprise software companies.$q$, $q$Initial proofs of concept can often be implemented within days, but full production deployments, usually part of a broader quote-to-cash transformation project, typically take three to six months to complete.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e21bbe8e-03eb-4184-be8d-54e23a99ca1f', $q$All-in-one mail daemon$q$, $q$Combines MTA, MX, and IMAP functionality into a single Go binary instead of requiring separate Postfix and Dovecot installations.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e21bbe8e-03eb-4184-be8d-54e23a99ca1f', $q$Built-in email authentication$q$, $q$Natively implements DKIM, SPF, DMARC, DANE, and MTA-STS to keep outbound mail authenticated and out of spam filters.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e21bbe8e-03eb-4184-be8d-54e23a99ca1f', $q$Unified configuration$q$, $q$A single configuration file controls SMTP, IMAP, filtering, authentication, and local delivery rules.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e21bbe8e-03eb-4184-be8d-54e23a99ca1f', $q$Flexible storage backends$q$, $q$Supports local filesystem storage as well as Amazon S3-compatible blob storage for mailboxes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e21bbe8e-03eb-4184-be8d-54e23a99ca1f', $q$Multiple authentication methods$q$, $q$Integrates with PAM, system commands, or LDAP for user authentication.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e21bbe8e-03eb-4184-be8d-54e23a99ca1f', $q$Docker support$q$, $q$Ships official Docker images for straightforward containerized deployment.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e21bbe8e-03eb-4184-be8d-54e23a99ca1f', $q$SMTP/LMTP forwarding$q$, $q$Supports remote MX delivery and forwarding to downstream mail systems.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e21bbe8e-03eb-4184-be8d-54e23a99ca1f', $q$Lightweight Go codebase$q$, $q$Written entirely in Go, making it lightweight, fast, and relatively easy to audit compared to older C-based mail daemons.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e21bbe8e-03eb-4184-be8d-54e23a99ca1f', $q$Free and open source with no licensing costs.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e21bbe8e-03eb-4184-be8d-54e23a99ca1f', $q$Replaces a stack of separate daemons, including Postfix, Dovecot, OpenDKIM, OpenSPF, and OpenDMARC, with one binary and one config file.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e21bbe8e-03eb-4184-be8d-54e23a99ca1f', $q$Modern Go codebase that is easier to audit and deploy than legacy C-based mail servers.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e21bbe8e-03eb-4184-be8d-54e23a99ca1f', $q$Native support for the full modern email security stack, including DANE and MTA-STS.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e21bbe8e-03eb-4184-be8d-54e23a99ca1f', $q$Official Docker images simplify self-hosted deployment.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e21bbe8e-03eb-4184-be8d-54e23a99ca1f', $q$GPLv3 license requires derivative distributed works to also be open source, which can be a constraint for commercial products.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e21bbe8e-03eb-4184-be8d-54e23a99ca1f', $q$Smaller community and ecosystem than long-established projects like Postfix and Dovecot.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e21bbe8e-03eb-4184-be8d-54e23a99ca1f', $q$Fewer turnkey management interfaces or admin panels compared to bundled solutions like Mailcow.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e21bbe8e-03eb-4184-be8d-54e23a99ca1f', $q$Running any self-hosted mail server, including Maddy, requires ongoing sysadmin effort for deliverability and security.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e21bbe8e-03eb-4184-be8d-54e23a99ca1f', $q$As a newer project, it has a smaller track record in large-scale production deployments compared to decades-old mail server software.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e21bbe8e-03eb-4184-be8d-54e23a99ca1f', $q$Is Maddy Mail Server free?$q$, $q$Yes, Maddy is completely free and open source, licensed under the GNU General Public License version 3.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e21bbe8e-03eb-4184-be8d-54e23a99ca1f', $q$What does Maddy replace?$q$, $q$Maddy is designed to replace the combination of Postfix, Dovecot, OpenDKIM, OpenSPF, and OpenDMARC with a single unified mail server daemon.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e21bbe8e-03eb-4184-be8d-54e23a99ca1f', $q$What language is Maddy written in?$q$, $q$Maddy is written entirely in the Go programming language.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e21bbe8e-03eb-4184-be8d-54e23a99ca1f', $q$Does Maddy support DKIM, SPF, and DMARC?$q$, $q$Yes, Maddy natively implements DKIM, SPF, DMARC, DANE, and MTA-STS for modern email authentication and security.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e21bbe8e-03eb-4184-be8d-54e23a99ca1f', $q$Who created Maddy Mail Server?$q$, $q$Maddy was created by developer Max Mazurov, known online as foxcpp, and is maintained as an open-source project on GitHub.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e21bbe8e-03eb-4184-be8d-54e23a99ca1f', $q$Can Maddy run in Docker?$q$, $q$Yes, Maddy provides official Docker images for containerized deployment.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e21bbe8e-03eb-4184-be8d-54e23a99ca1f', $q$Self-hosted email for small organizations$q$, $q$Small businesses and organizations run Maddy to host their own email without relying on a third-party provider.$q$, $q$Small businesses and sysadmins$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e21bbe8e-03eb-4184-be8d-54e23a99ca1f', $q$Privacy-focused personal email$q$, $q$Privacy-conscious individuals self-host Maddy to keep full control over their own mailboxes and data.$q$, $q$Privacy-focused individuals$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e21bbe8e-03eb-4184-be8d-54e23a99ca1f', $q$Simplified mail infrastructure for developers$q$, $q$Developers who want a single, easy-to-configure mail daemon instead of managing Postfix and Dovecot separately choose Maddy for test and production environments.$q$, $q$Developers and DevOps engineers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e21bbe8e-03eb-4184-be8d-54e23a99ca1f', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full MTA, MX, and IMAP functionality","Built-in DKIM, SPF, DMARC, DANE, and MTA-STS","Docker images","Community support only"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e21bbe8e-03eb-4184-be8d-54e23a99ca1f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Maddy Mail Server is a free, open-source, self-hosted mail server written in Go that consolidates the many components of a traditional email stack, an MTA, an MX server, an IMAP server, and separate DKIM, SPF, DMARC, DANE, and MTA-STS services, into one binary with a single configuration file. It was created by developer Max Mazurov (foxcpp), with the project dating from around 2019, and is maintained on GitHub with dozens of community contributors.$q$, $q$Maddy is aimed at technically capable self-hosters and small organizations who want to run their own email infrastructure without separately installing and configuring Postfix, Dovecot, OpenDKIM, OpenSPF, and OpenDMARC, trading some of the flexibility of those mature, individually specialized daemons for a simpler, unified setup.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e21bbe8e-03eb-4184-be8d-54e23a99ca1f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Maddy can send mail as an MTA, receive mail as an MX server, and store and serve mailboxes over IMAP, all from a single daemon. It natively implements the modern email authentication and security stack, DKIM, SPF, DMARC, DANE, and MTA-STS, that major providers increasingly require to keep outbound mail out of spam folders.$q$, $q$The server supports flexible storage backends including local filesystem and Amazon S3-compatible blob storage, multiple authentication methods including PAM, system commands, and LDAP, and official Docker images for containerized deployment.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e21bbe8e-03eb-4184-be8d-54e23a99ca1f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Maddy Mail Server is completely free and open source, with no paid tiers, licenses, or subscriptions. It is licensed under the GNU General Public License version 3, having switched from the original MIT license starting with version 0.3.3/0.4.$q$, $q$Because it is self-hosted, the only real costs are the server or cloud instance running it; there is no vendor to pay and no usage-based fees.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e21bbe8e-03eb-4184-be8d-54e23a99ca1f', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e21bbe8e-03eb-4184-be8d-54e23a99ca1f', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$Notebook-style pipeline builder$q$, $q$Build real-time and batch data pipelines using Python, SQL, and R inside an interactive, notebook-like development environment.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$Built-in orchestration and scheduling$q$, $q$Native scheduling and orchestration remove the need to bolt on a separate workflow orchestrator like Airflow.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$Pipeline versioning and observability$q$, $q$Tracks pipeline changes and surfaces run history and monitoring without extra tooling.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$Open-source, self-hosted core$q$, $q$The MIT-licensed open-source edition can be deployed on a user's own infrastructure at no cost.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$Managed cloud (Mage Pro)$q$, $q$A fully managed cloud deployment removes infrastructure setup, maintenance, and update burden.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$Hybrid and private-cloud deployment$q$, $q$Enterprise customers can keep data processing inside their own private cloud while Mage manages the control plane, or run the entire platform privately.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$Multi-region availability$q$, $q$Regional deployment options span the US, Canada, Europe, Asia, and Australia.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$Compute-based billing$q$, $q$Paid Mage Pro tiers combine a base subscription fee with per-compute-hour usage charges.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$Free, MIT-licensed open-source core with no cost to self-host.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$Unified support for Python, SQL, and R in a single pipeline, reducing tool sprawl.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$Notebook-style interface lowers the learning curve compared to code-only orchestrators like Airflow.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$Clear upgrade path from free open source to a managed commercial product, Mage Pro, without switching tools.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$Flexible deployment options, including private-cloud and hybrid configurations for enterprises with data residency requirements.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$Mage Pro pricing combines a base subscription with per-compute-hour charges, which can be harder to predict than flat-rate pricing.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$Smaller ecosystem and community than long-established orchestrators like Apache Airflow.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$Enterprise tier pricing, around $25,000/month, is a significant commitment for large organizations.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$As a younger, venture-backed company, long-term roadmap and support depend on continued funding or revenue growth.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$Notebook-style pipelines may be less familiar to teams standardized on pure code-based orchestration like Airflow DAGs.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$Is Mage.ai free?$q$, $q$Yes, Mage's open-source core is free and MIT-licensed and can be self-hosted at no cost; the paid Mage Pro product adds managed cloud hosting and enterprise features.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$What languages does Mage support for pipelines?$q$, $q$Mage pipelines can be built using Python, SQL, and R within its notebook-style interface.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$How much does Mage Pro cost?$q$, $q$Mage Pro starts at around $100/month for the Starter plan plus $0.29 per compute hour, with Team, Plus, Business, and Enterprise tiers scaling up to roughly $25,000/month.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$Who founded Mage.ai?$q$, $q$Mage was founded in 2020 by Tommy Dang and Xiaoyou Wang and is headquartered in Santa Clara, California.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$Can Mage be deployed in a private cloud?$q$, $q$Yes, Mage Pro supports hybrid deployment, where the control plane runs in Mage's cloud but data processing stays in the customer's private cloud, as well as fully private-cloud deployment.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$What are Mage's main competitors?$q$, $q$Mage competes with Apache Airflow, Dagster, Prefect, and dbt in the data pipeline and orchestration space.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$ETL/ELT pipeline development$q$, $q$Data engineers use Mage to build and orchestrate pipelines that extract, transform, and load data between systems.$q$, $q$Data engineers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$Analytics engineering workflows$q$, $q$Analytics teams use Mage's SQL and Python support to build transformation pipelines feeding dashboards and reports.$q$, $q$Analytics engineers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$Enterprise data platform governance$q$, $q$Larger organizations adopt Mage Pro's hybrid or private-cloud deployment to run governed, collaborative pipelines while keeping data within their own infrastructure.$q$, $q$Enterprise data platform teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Self-hosted deployment","Python, SQL, and R pipelines","Built-in orchestration and scheduling","MIT license"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$Mage Pro Starter$q$, $q$About $100/month plus $0.29 per compute hour$q$, $q$monthly$q$, NULL, $q$["Managed cloud hosting","Basic collaboration features"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$Mage Pro Team$q$, $q$About $500/month plus compute usage$q$, $q$monthly$q$, NULL, $q$["Team collaboration","Increased usage limits"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$Mage Pro Plus$q$, $q$About $2000/month plus compute usage$q$, $q$monthly$q$, NULL, $q$["Expanded collaboration and governance","Higher usage limits"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$Mage Pro Business$q$, $q$About $5500/month plus compute usage$q$, $q$monthly$q$, NULL, $q$["Advanced governance","Priority support"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$Mage Pro Enterprise$q$, $q$About $25000/month plus compute usage$q$, $q$monthly$q$, NULL, $q$["Private or hybrid cloud deployment","Dedicated support","Enterprise-grade governance"]$q$::jsonb, 5);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Mage, or Mage.ai, is an open-source data pipeline and orchestration tool for building, running, and managing ETL/ELT workflows that integrate and transform data. It was founded in 2020 by Tommy Dang and Xiaoyou Wang and is headquartered in Santa Clara, California, having raised roughly $11.8 million in seed funding led by Google's Gradient Ventures.$q$, $q$The project's core premise is consolidating data ingestion, transformation, and orchestration, traditionally handled by separate tools like Airflow, dbt, and Fivetran, into a single open-source platform with a notebook-style development experience, reducing both custom glue code and deployment complexity for data teams.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Mage lets users build real-time and batch data pipelines using Python, SQL, and R within an interactive, notebook-like interface, with built-in scheduling, orchestration, versioning, and pipeline observability rather than requiring separate tools bolted together.$q$, $q$The commercial Mage Pro product extends the open-source core with managed cloud hosting, hybrid and private-cloud deployment options, team collaboration and governance features, and regional deployment availability across the US, Canada, Europe, Asia, and Australia.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Mage's open-source core is free and MIT-licensed, and can be self-hosted at no cost. Mage Pro, the managed commercial product, starts with a Starter plan at around $100/month plus $0.29 per compute hour, moving up through Team, Plus, and Business tiers.$q$, $q$At the top end, Mage Pro's Enterprise plan runs around $25,000/month, with every paid tier billed on top of a base compute-hour rate that resets monthly along with block runs and AI token usage.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1d48d5fd-47e9-414e-af53-a8687df65dbb', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Catalog and inventory management$q$, $q$Manages complex product catalogs, variants, and inventory across single or multiple stores.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Integrated checkout and payments$q$, $q$Built-in checkout flow with support for numerous payment and shipping integrations.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Multi-store and multi-currency support$q$, $q$Runs multiple storefronts and currencies from a single Magento Open Source installation.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$WYSIWYG page builder$q$, $q$Lets merchandisers build and edit storefront pages visually without writing code.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Marketplace extensions$q$, $q$Access to the Adobe Commerce (Magento) Marketplace for third-party extensions and themes.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Mobile-optimized storefronts$q$, $q$Responsive, mobile-friendly storefront templates out of the box.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Modular PHP architecture$q$, $q$Built on PHP and MySQL/MariaDB with a modular codebase that developers can extensively customize.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Global selling support$q$, $q$Supports selling to international markets with localization and multi-currency capabilities.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$No license fee, giving merchants full source-code access and control at zero software cost.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Deep extensibility and customization through a modular architecture and large extension marketplace.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Large, established global ecosystem of Magento developers and specialized agencies.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Clear upgrade path to Adobe Commerce for merchants that later need enterprise features or managed hosting.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Backed by Adobe, giving the platform long-term corporate stability compared to smaller open-source e-commerce projects.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Requires merchants to source, secure, and manage their own hosting, unlike managed platforms such as Shopify.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Total cost of ownership, including hosting, development, extensions, and maintenance, can be substantial despite the free license.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Lacks Adobe Commerce's built-in B2B features, AI personalization, and enterprise SLA.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Steeper technical learning curve than hosted platforms like Shopify or BigCommerce.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Requires ongoing developer resources for updates, security patches, and performance optimization.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Is Magento Open Source really free?$q$, $q$Yes, the Magento Open Source software license is free, but merchants must pay separately for hosting, development, extensions, and ongoing maintenance.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$What is the difference between Magento Open Source and Adobe Commerce?$q$, $q$Magento Open Source is the free, self-hosted core platform, while Adobe Commerce is Adobe's paid enterprise tier that adds managed cloud hosting, built-in B2B features, AI personalization via Adobe Sensei, dedicated support, and an uptime SLA.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Who owns Magento now?$q$, $q$Adobe has owned Magento since completing its $1.68 billion acquisition of Magento Commerce in June 2018.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$When was Magento founded?$q$, $q$Magento's first general-availability release was published in March 2008 by Varien Inc., after development began in 2007.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$How much does it cost to run a Magento Open Source store?$q$, $q$While the software license is free, realistic total costs including hosting, development, extensions, and maintenance commonly range from roughly $122,000 to $450,000 or more per year for a full implementation.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$What are the alternatives to Magento Open Source?$q$, $q$Common alternatives include Shopify Plus, WooCommerce, BigCommerce, Shopware, and Adobe's own paid Adobe Commerce tier.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Custom mid-market e-commerce$q$, $q$Mid-sized merchants with in-house or agency development resources use Magento Open Source to build highly customized storefronts.$q$, $q$Mid-market retailers and brands$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Multi-store international retail$q$, $q$Merchants selling across multiple countries and currencies use Magento Open Source's multi-store architecture to manage several storefronts from one installation.$q$, $q$International and multi-brand retailers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Agency-built e-commerce projects$q$, $q$Development agencies build and maintain client stores on Magento Open Source, leveraging its large extension ecosystem and developer talent pool.$q$, $q$E-commerce development agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Magento Open Source$q$, $q$Free (software license)$q$, $q$N/A$q$, NULL, $q$["Core commerce engine","Self-hosted deployment","Marketplace extension access","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$Adobe Commerce (upgrade path)$q$, $q$From about $22000/year$q$, $q$annual$q$, NULL, $q$["Managed cloud hosting option","Built-in B2B features","AI personalization via Adobe Sensei","24/7 Adobe support","99.99% uptime SLA"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Magento Open Source is Adobe's free, self-hosted edition of the Magento e-commerce platform, containing the core commerce engine without the advanced features reserved for the paid Adobe Commerce tier. Magento was originally built by Varien Inc., launching its first general-availability release in March 2008, before eBay acquired it in stages between 2010 and 2011 and Adobe ultimately bought Magento Commerce for $1.68 billion in June 2018.$q$, $q$Today Magento Open Source sits alongside Adobe Commerce as the free, community-oriented entry point into the Magento ecosystem, aimed at merchants and development teams who want full control over customization and hosting rather than a fully managed, paid enterprise platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Magento Open Source includes catalog and inventory management, an integrated checkout, payment and shipping workflow, multi-store and multi-currency support, a WYSIWYG page builder, and mobile-optimized storefronts, all built on a modular PHP and MySQL/MariaDB architecture that merchants self-host.$q$, $q$It provides access to the Adobe Commerce (Magento) Marketplace for extensions and themes, letting merchants extend functionality, but excludes Adobe Commerce-only capabilities such as built-in B2B tools, Adobe Sensei-powered AI personalization, managed AWS cloud hosting, dedicated 24/7 support, and a contractual uptime SLA.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Magento Open Source itself carries no license fee and is free to download and use. However, merchants are responsible for their own hosting, security, performance tuning, extensions, and ongoing development, so realistic total costs of ownership can run well into six figures annually for a full implementation.$q$, $q$Merchants who outgrow Magento Open Source's self-managed model can upgrade to Adobe Commerce, which starts at roughly $22,000 per year for smaller merchants and scales past $125,000 per year for larger ones, adding managed hosting, B2B features, AI personalization, and enterprise-grade support.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a4b8ce3e-bd25-4482-8847-63041b2784ea', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
