-- Enrichment marathon batch: Lunatask, Lunch Money, Lusha, Lyrion Music Server, m3ter, Maddy Mail Server, Mage, Magento Open Source

-- ── Lunatask ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Lunatask is an end-to-end encrypted task manager, habit tracker, journal, and notes app built specifically for people with ADHD, available on Mac, Windows, Linux, iOS, and Android.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Premium from $8/month or $72/year; lifetime option $300)$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE($q$Independent / solo developer$q$, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Lunatask Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Lunatask review 2026: an encrypted, ADHD-friendly task manager with habit tracking and journaling. See pricing, features, pros and cons, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Lunatask is an all-in-one personal productivity application that combines a to-do list, habit and mood tracker, journal, notes, and a lightweight personal CRM into a single end-to-end encrypted workspace. It was built by independent developer Carl Pullein and released in 2021 after Pullein, who has ADHD, grew frustrated that mainstream task managers such as Todoist, Things, and OmniFocus were not designed around the way ADHD brains prioritize and get overwhelmed by long lists. Lunatask's core design principle is to show users only what they can act on right now rather than an intimidating wall of tasks, using features like a 'now/next/later' priority system, an Eisenhower Matrix view, and Kanban boards to help users triage work without decision paralysis. Technically, Lunatask stores nearly everything client-side and end-to-end encrypted before it ever reaches Lunatask's sync servers, using the argon2 key-derivation function (implemented in WebAssembly) for password-based key generation and TLS 1.3 for transport security. This means the company itself cannot read a user's tasks, journal entries, habit logs, or notes, which is a differentiator against mainstream competitors that store data in plaintext on their servers. The app ships as native or near-native clients for macOS, Windows, Linux, iOS, and Android, with data syncing across all of them. Beyond task management, Lunatask includes a habit tracker that logs daily habits and mood and surfaces patterns between the two, a private journal with mood and emotion tagging, freeform notes, and a simple relationship/CRM module for keeping track of personal contacts and follow-ups. Tasks can be organized into 'Areas of Life' (for example Work, Health, Family) to give a bird's-eye view of how effort is distributed. Lunatask uses a freemium pricing model. The free tier is usable indefinitely but caps users at 2 Areas of Life, 7 daily habits, and 30 CRM relationships, and does not include calendar integration. The Premium tier unlocks unlimited areas, habits, and relationships, plus calendar integration and all viewing modes, for $8/month billed monthly or $72/year (effectively $6/month) billed annually. Lunatask also offers a one-time lifetime Premium license for $300, an unusual option among modern subscription productivity tools. Lunatask's target audience is individuals, largely knowledge workers, neurodivergent users, and privacy-conscious professionals, rather than teams; it has no team collaboration, shared-workspace, or multi-user administration features, which sets it apart from competitors like Todoist, ClickUp, or Notion. Its closest competitors are other single-user, privacy-focused productivity apps such as TickTick, Things 3, Sunsama, and Amazing Marvin, with Lunatask differentiating itself primarily through its client-side encryption model and explicit ADHD-oriented design language of reduced visual clutter, forced prioritization, and habit-mood correlation.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'a0d8e5e2-0822-4d08-807a-6b9e49ebe1b0';

