-- ── Lunch Money ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Lunch Money is a web and mobile personal budgeting app that syncs bank and crypto accounts across multiple currencies, sold on a pay-what-you-want subscription model.$q$, short_description),
  pricing_model = COALESCE($q$Subscription (pay-what-you-want)$q$, pricing_model),
  starting_price = COALESCE($q$Free trial, then pay-what-you-want (originally launched at $3/month)$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$Small, bootstrapped team$q$, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Lunch Money Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Lunch Money review 2026: a pay-what-you-want budgeting app with bank sync, multi-currency support, and shared budgets. Pricing, features, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Lunch Money is a web-based, with companion mobile apps, personal finance and budgeting tool that connects to bank accounts, credit cards, investment accounts, and even cryptocurrency wallets to give users a consolidated view of spending, budgets, and net worth. It was founded by Jen Yip, a solo developer who spent roughly a year and a half manually tracking her own multi-currency spending in a spreadsheet while traveling through Europe and Asia during a career break, before turning that spreadsheet into a product. Lunch Money launched publicly in 2019 via Hacker News' Show HN, and for its first several years Yip ran the company alone, handling engineering, design, support, and marketing herself. Lunch Money is bootstrapped and has not raised outside venture funding; it is entirely funded by subscription revenue, which the company has cited as core to its philosophy of building a product for its users rather than for investors. Its signature pricing mechanic is a pay-what-you-want annual subscription: after a free trial, users choose their own price, subject to a minimum, and that price is locked in for as long as they remain subscribed, rewarding early and loyal customers with lower rates than new sign-ups might pay later. The app originally launched at $3/month ($29/year) in 2019; suggested pricing has since risen, though the pay-what-you-want structure means actual prices vary by user and all plans include the full feature set rather than gating features behind tiers. Functionally, Lunch Money aggregates transactions from linked bank and investment accounts via an account-aggregation provider, supports manual account tracking for cash or crypto, and lets users build zero-based or category budgets, tag and split transactions, track recurring bills, and view multi-currency balances converted into a home currency. It supports shared household budgets so partners can track joint finances, and offers a public API and integrations for users who want to build custom automations, appealing to a technically inclined user base. Lunch Money's target audience is individuals and couples who find automated apps too rigid and spreadsheet-based budgeting too manual, particularly freelancers, remote workers, expats, and crypto-curious users who need reliable multi-currency support. Its main competitors include YNAB (You Need A Budget), Copilot Money, Monarch Money, Tiller, and Actual Budget, with Lunch Money differentiating itself through its unusual pay-what-you-want pricing, strong multi-currency and crypto support, and a developer-friendly API, all built and supported by a small, founder-led team rather than a large venture-backed company.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '9b18967c-f6f6-453b-8f0e-8b8d312dfe53';

