-- ── Lyrion Music Server ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Lyrion Music Server is a free, open-source, community-maintained media server, the successor to Logitech Media Server and Squeezebox Server, that streams personal music libraries to networked players.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2001, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Lyrion Music Server Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Lyrion Music Server review 2026: the free, open-source successor to Logitech Media Server. Features, setup, pricing, pros and cons, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Lyrion Music Server (LMS) is a free, open-source media server for streaming personal digital music collections to a wide range of players, from dedicated Squeezebox hardware to third-party apps and smart speakers. Its history traces back to 2001, when Slim Devices released SlimServer alongside its SLIMP3 network audio player; the server software was later renamed SqueezeCenter and then Squeezebox Server as Slim Devices' hardware line evolved. Logitech acquired Slim Devices in 2006 and rebranded the server as Logitech Media Server while continuing to sell Squeezebox hardware players. Logitech discontinued Squeezebox hardware and stepped back from active development after version 7.7; from version 7.8 onward, starting March 2014, the software was maintained entirely by a volunteer community under the LMS-Community organization on GitHub, continuing through the 8.x release series. After Logitech shut down its associated mysqueezebox.com cloud service in March 2024, the community completed its separation from the Logitech brand by rebranding the project as Lyrion Music Server with the release of version 9.0 in November 2024, continuing the version numbering lineage from the 8.x series. Lyrion Music Server is written primarily in Perl and is licensed under the GNU General Public License. It runs on Linux, Windows, macOS, and BSD, and is commonly deployed on NAS devices from vendors like Synology and QNAP, as well as on minimal Linux distributions such as piCorePlayer built specifically for audio streaming. The server indexes a local music library and streams audio in formats including MP3, FLAC, WAV, Ogg Vorbis, Opus, and AAC to any number of connected players, supporting synchronized multi-room playback across grouped clients. Because it descends directly from Logitech Media Server, Lyrion Music Server remains compatible with the installed base of Squeezebox hardware players as well as newer software players like Squeezelite and third-party apps such as Material Skin, giving it a large library of client software despite the original hardware being long discontinued. A plugin architecture extends functionality to support internet radio, streaming services, and custom integrations. Because Lyrion is free, open-source, and self-hosted, it has no direct commercial competitors in the traditional sense; its closest comparisons are other self-hosted media and streaming servers such as Plex, Jellyfin, Navidrome, and Roon, a paid commercial alternative, with Lyrion differentiating itself through its long history with the Squeezebox ecosystem, its multi-room synchronized playback, and its fully community-governed, non-commercial development model. Its target audience is audiophiles and home-server hobbyists who already own or want to build networked audio systems and prefer self-hosting their music library over relying on streaming services alone.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'afe3197a-f0df-4980-b89c-90bb6be2715d';

