-- ── m3ter ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$m3ter is an enterprise usage-metering and rating platform that powers consumption-based billing for software companies, acquired by Salesforce in 2026 to power Agentforce Revenue Management.$q$, short_description),
  pricing_model = COALESCE($q$Custom / Enterprise quote-based$q$, pricing_model),
  starting_price = COALESCE($q$Custom pricing, typically six-figure annual enterprise contracts$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$London, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$m3ter Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$m3ter review 2026: enterprise usage-metering and billing platform now part of Salesforce. Features, pricing, pros and cons, and top alternatives compared.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$m3ter is an enterprise-grade usage-metering, rating, and pricing operations platform built to help software and SaaS companies run consumption-based and hybrid billing models at scale. It was founded in 2020 in London, United Kingdom, by Griffin Parry and John Griffin, who had previously co-founded GameSparks, a cloud backend services company for game developers that was acquired by Amazon Web Services in 2017. m3ter raised institutional funding to build out its platform, including a $17.5 million seed round backed by investors such as Union Square Ventures, Insight Partners, and Kindred Capital, followed by a $14 million Series A round led by Notion Capital in 2023, bringing its total funding to roughly $33 million before it was acquired. In June 2026, Salesforce signed a definitive agreement to acquire m3ter, with the deal closing on July 1, 2026. Salesforce integrated m3ter's high-volume mediation, metering, and rating engine into Agentforce Revenue Management, its billing and monetization layer for AI agent and consumption-based pricing, positioning m3ter's technology as core infrastructure for billing AI-agent usage and outcome-based pricing models across the Salesforce ecosystem. Architecturally, m3ter is built to ingest very high volumes of usage events in real time, apply complex, multi-dimensional pricing and rating logic across tiered, graduated, per-unit, or hybrid pricing spanning multiple metrics, and generate accurate, auditable bills that integrate downstream with invoicing, CRM, and revenue-recognition systems such as Salesforce, NetSuite, and Stripe Billing. Rather than being a full end-to-end billing and payments platform, m3ter has historically focused specifically on the metering and rating layer of the quote-to-cash process, the hardest part of usage-based billing to get right at scale, while relying on integrations for invoicing, tax, dunning, and payment collection. m3ter does not publish self-serve pricing; contracts are negotiated per customer and typically represent six-figure annual commitments, reflecting its target market of mid-market to large enterprise software companies undertaking a broader quote-to-cash transformation rather than small startups. Initial proof-of-concept implementations can be stood up in days, but full production rollouts as part of a broader billing overhaul commonly take three to six months. m3ter's primary competitors in the usage-based billing and metering space include Metronome, Amberflo, Togai, Orb, and larger billing platforms like Zuora, Chargebee, and BillingPlatform. Its differentiation has centered on deep metering and rating sophistication for complex, high-volume pricing models, now amplified by its integration into Salesforce's broader CRM and revenue-management ecosystem following the 2026 acquisition.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'a6963e7b-5db0-4f3f-a759-a0c758f52263';

