-- ── Maddy Mail Server ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Maddy Mail Server is a free, open-source, all-in-one mail server written in Go that replaces Postfix, Dovecot, and related daemons with a single composable binary.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$Independent open-source project$q$, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Maddy Mail Server Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Maddy Mail Server review 2026: a free, open-source, all-in-one Go mail server. Features, setup, licensing, pros and cons, and self-hosted alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Maddy Mail Server, often written as 'maddy,' is a free, open-source, self-hosted mail server written entirely in the Go programming language. It was created by developer Max Mazurov, known online as foxcpp, with the project's copyright dating from around 2019, and is maintained on GitHub as foxcpp/maddy with contributions from a community of dozens of contributors. Maddy's core design goal is to consolidate the many separate daemons traditionally required to run a full email server, an MTA like Postfix for sending mail, an MX or receiving component, an IMAP server like Dovecot for storage and retrieval, plus separate services for DKIM signing, SPF checking, DMARC enforcement, DANE, and MTA-STS, into a single binary with one unified configuration file. Functionally, Maddy can operate as a full mail transfer agent sending outbound mail via SMTP, as an MX server accepting inbound mail via SMTP, and as an IMAP server storing and serving mailboxes to mail clients, while natively implementing the modern email-authentication and security stack, DKIM, SPF, DMARC, DANE, and MTA-STS, that is increasingly required by major mail providers like Gmail and Outlook to avoid spam filtering. It supports flexible storage and delivery backends, including local filesystem storage, Amazon S3-compatible blob storage, local delivery queues, remote MX delivery, and SMTP/LMTP forwarding to downstream systems, along with authentication via PAM, system commands, or LDAP for integrating with existing user directories. Official Docker images are provided for containerized deployment, which is a common way Maddy is run in self-hosting communities. Maddy's license changed from the permissive MIT license to the copyleft GNU General Public License version 3 starting with version 0.3.3/0.4 and all subsequent releases, meaning any distributed modified versions must also be open-sourced under GPLv3 terms, a notable consideration for companies wanting to build proprietary products on top of it. As a fully open-source, self-hosted tool, Maddy has no commercial pricing; it is entirely free to download, configure, and run on a user's own server. Its target audience is technically proficient self-hosters, small businesses, privacy-focused individuals, and sysadmins who want to run their own email infrastructure without maintaining separately configured Postfix, Dovecot, OpenDKIM, and OpenSPF/OpenDMARC installations. Its main alternatives in the self-hosted mail server space include Postfix combined with Dovecot, Mailcow, Mail-in-a-Box, and Stalwart Mail Server, with Maddy differentiating itself through its single-binary, single-config-file simplicity and its modern Go codebase, at the cost of a smaller user base and fewer turnkey management interfaces than some of those alternatives.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
